import React, { useState } from 'react';
import PizzaList from './components/PizzaList';
import PizzaModal from './components/PizzaModal';
import pizzaImage from './pizza.png';
import logoImage from './logo.png';
import vectorImage from './Vector.png';
import {
  PageWrapper,
  Main,
  Container,
  Header,
  HeaderContent,
  HeaderLabel,
  LogoImage,
  CartText,
  Banner,
  BannerText,
  Category,
  Title,
  Footer,
  FooterText,
  GlobalStyle,
  CartOverlay,
  CartDrawer,
  CartHeader,
  CartItems,
  CartItem,
  CartItemImage,
  CartItemInfo,
  CartItemName,
  CartItemPrice,
  CartDivider,
  CartTotal,
  CartButton,
  CloseCart,
  CheckoutTitle,
  FormField,
  FormLabel,
  FormInput,
  FormActions,
  BackButton
} from './styles/styles';

// Dados de exemplo para pizzas
const pizzas = [
  {
    id: 1,
    name: 'Margherita',
    description: 'Molho de tomate, mussarela, manjericão fresco.',
    price: 25.99,
    image: pizzaImage,
  },
  {
    id: 2,
    name: 'Pepperoni',
    description: 'Molho de tomate, mussarela, pepperoni.',
    price: 29.99,
    image: pizzaImage,
  },
  {
    id: 3,
    name: 'Quatro Queijos',
    description: 'Molho de tomate, mussarela, gorgonzola, parmesão, provolone.',
    price: 32.99,
    image: pizzaImage,
  },
];

function App() {
  const [cartOpen, setCartOpen] = useState(false);
  const [cartItems, setCartItems] = useState([]);
  const [selectedPizza, setSelectedPizza] = useState(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [checkoutOpen, setCheckoutOpen] = useState(false);
  const [address, setAddress] = useState('');
  const [number, setNumber] = useState('');
  const [complement, setComplement] = useState('');
  const [city, setCity] = useState('');
  const [cep, setCep] = useState('');

  const handleAddToCart = (pizza) => {
    setCartItems((prev) => {
      const found = prev.find((item) => item.id === pizza.id);
      if (found) {
        return prev.map((item) =>
          item.id === pizza.id
            ? { ...item, quantity: item.quantity + 1 }
            : item
        );
      }
      return [...prev, { ...pizza, quantity: 1 }];
    });
  };

  const openCart = () => {
    setCartOpen(true);
    setCheckoutOpen(false);
  };
  const closeCart = () => setCartOpen(false);
  const openCheckout = () => setCheckoutOpen(true);
  const backToCart = () => setCheckoutOpen(false);

  const handlePizzaClick = (pizza) => {
    setSelectedPizza(pizza);
    setIsModalOpen(true);
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
    setSelectedPizza(null);
  };

  const totalItems = cartItems.reduce((sum, item) => sum + item.quantity, 0);
  const totalPrice = cartItems
    .reduce((sum, item) => sum + item.quantity * item.price, 0)
    .toFixed(2);

  return (
    <PageWrapper>
      <GlobalStyle />
      <Header image={vectorImage}>
        <Container>
          <HeaderContent>
            <HeaderLabel>Restaurante</HeaderLabel>
            <LogoImage src={logoImage} alt="Efood" />
            <CartText onClick={openCart} style={{ cursor: 'pointer' }}>
              Carrinho ({totalItems})
            </CartText>
          </HeaderContent>
        </Container>
      </Header>
      <Main>
        <Banner image={pizzaImage}>
          <Container>
            <BannerText>
              <Category>Italiana</Category>
              <Title>La Dolce Vita Trattoria</Title>
            </BannerText>
          </Container>
        </Banner>
        <Container>
          <PizzaList
            pizzas={pizzas}
            onPizzaClick={handlePizzaClick}
            onAddToCart={handleAddToCart}
          />
        </Container>
      </Main>

      {cartOpen && (
        <CartOverlay onClick={closeCart}>
          <CartDrawer onClick={(e) => e.stopPropagation()}>
            <CartHeader>
              <div>{checkoutOpen ? 'Endereço de entrega' : 'Carrinho'}</div>
              <CloseCart onClick={closeCart}>&times;</CloseCart>
            </CartHeader>

            {checkoutOpen ? (
              <>
                <CheckoutTitle>Insira os dados da entrega</CheckoutTitle>
                <FormField>
                  <FormLabel>Endereço</FormLabel>
                  <FormInput value={address} onChange={(e) => setAddress(e.target.value)} />
                </FormField>
                <FormField>
                  <FormLabel>Número</FormLabel>
                  <FormInput value={number} onChange={(e) => setNumber(e.target.value)} />
                </FormField>
                <FormField>
                  <FormLabel>Complemento</FormLabel>
                  <FormInput value={complement} onChange={(e) => setComplement(e.target.value)} />
                </FormField>
                <FormField>
                  <FormLabel>Cidade</FormLabel>
                  <FormInput value={city} onChange={(e) => setCity(e.target.value)} />
                </FormField>
                <FormField>
                  <FormLabel>CEP</FormLabel>
                  <FormInput value={cep} onChange={(e) => setCep(e.target.value)} />
                </FormField>
                <FormActions>
                  <BackButton onClick={backToCart}>Voltar ao carrinho</BackButton>
                  <CartButton>Continuar pagamento</CartButton>
                </FormActions>
              </>
            ) : (
              <>
                <CartItems>
                  {cartItems.length === 0 ? (
                    <p>O carrinho está vazio.</p>
                  ) : (
                    cartItems.map((item) => (
                      <CartItem key={item.id}>
                        <CartItemImage src={item.image} alt={item.name} />
                        <CartItemInfo>
                          <CartItemName>{item.name}</CartItemName>
                          <CartItemPrice>
                            {item.quantity} x R$ {item.price.toFixed(2)}
                          </CartItemPrice>
                        </CartItemInfo>
                      </CartItem>
                    ))
                  )}
                </CartItems>
                <CartDivider />
                <CartTotal>
                  <span>Valor total</span>
                  <strong>R$ {totalPrice}</strong>
                </CartTotal>
                <CartButton onClick={openCheckout}>Continuar com a entrega</CartButton>
              </>
            )}
          </CartDrawer>
        </CartOverlay>
      )}

      <Footer>
        <Container>
          <FooterText>© 2023 Efood. Todos os direitos reservados.</FooterText>
        </Container>
      </Footer>

      {isModalOpen && selectedPizza && (
        <PizzaModal
          pizza={selectedPizza}
          onClose={handleCloseModal}
          onAddToCart={handleAddToCart}
        />
      )}
    </PageWrapper>
  );
}

export default App;
